#include <optional>
using namespace llvm;

static std::optional<APInt> evaluateBinaryOperator(unsigned Opcode,
                                                   const APInt &LHS,
                                                   const APInt &RHS) {
  switch (Opcode) {
  case Instruction::Add:
    return LHS + RHS;
  case Instruction::Sub:
    return LHS - RHS;
  case Instruction::Mul:
    return LHS * RHS;
  case Instruction::SDiv:
    if (RHS.isZero())
      return std::nullopt;
    return LHS.sdiv(RHS);
  case Instruction::UDiv:
    if (RHS.isZero())
      return std::nullopt;
    return LHS.udiv(RHS);
  case Instruction::Shl:
    if (RHS.uge(LHS.getBitWidth()))
      return std::nullopt;
    return LHS.shl(RHS);
  case Instruction::LShr:
    if (RHS.uge(LHS.getBitWidth()))
      return std::nullopt;
    return LHS.lshr(RHS);
  case Instruction::AShr:
    if (RHS.uge(LHS.getBitWidth()))
      return std::nullopt;
    return LHS.ashr(RHS);
  case Instruction::And:
    return LHS & RHS;
  case Instruction::Or:
    return LHS | RHS;
  case Instruction::Xor:
    return LHS ^ RHS;
  default:
    return std::nullopt;
  }
}

// Takes \p Foo and apply a simple constant propagation optimization.
// \returns true if \p Foo was modified (i.e., something had been constant
// propagated), false otherwise.
bool myConstantPropagation(Function &Foo) {
  bool Changed = false;

  for (BasicBlock &BB : Foo) {
    for (Instruction &I : make_early_inc_range(BB)) {
      auto *BinOp = dyn_cast<BinaryOperator>(&I);
      if (!BinOp)
        continue;

      auto *LHS = dyn_cast<ConstantInt>(BinOp->getOperand(0));
      auto *RHS = dyn_cast<ConstantInt>(BinOp->getOperand(1));
      if (!LHS || !RHS)
        continue;

      std::optional<APInt> Result = evaluateBinaryOperator(
          BinOp->getOpcode(), LHS->getValue(), RHS->getValue());
      if (!Result)
        continue;

      auto *Folded = ConstantInt::get(BinOp->getType(), *Result);
      BinOp->replaceAllUsesWith(Folded);
      BinOp->eraseFromParent();
      Changed = true;
    }
  }

  return Changed;
}

